+//! Delta Outlier Analyzer for Zell v2.0
+//!
+//! Computes DELTA corrections: delta = Q4K_FP32 - Q2K_FP32
+//! These deltas allow the kernel to correct Q2K approximation:
+//!   result = Q2K_matmul(x, W_q2k) + sparse_matmul(x, deltas)
+//!         = Q2K * x + (Q4K - Q2K) * x = Q4K * x (correct!)
+//!
+//! Usage:
+//!   delta_outlier_analyzer <q4k_model.gguf> --virtual <output.csr>   (Virtual Q2 mode - RECOMMENDED)
+//!   delta_outlier_analyzer <q4k_model.gguf> <q2k_model.gguf> <output.csr>   (Two-file mode)
+
+const std = @import("std");
+const gguf_loader = @import("inference/gguf_loader.zig");
+const types = @import("inference/gguf/types.zig");
+const hybrid_quantizer = @import("hybrid_quantizer.zig");
+const quantize = @import("quantize.zig");
+
+const log = std.log.scoped(.delta_outlier);
+
+/// Analyze tensors from both models and compute delta corrections
+pub fn analyzeDeltaCorrections(
+    allocator: std.mem.Allocator,
+    q4k_loader: *gguf_loader.GGUFLoader,
+    q2k_loader: *gguf_loader.GGUFLoader,
+) ![]hybrid_quantizer.TensorCSR {
+    log.info("Starting delta outlier analysis...", .{});
+
+    var tensor_csrs = std.ArrayList(hybrid_quantizer.TensorCSR).initCapacity(allocator, 768) catch unreachable;
+    errdefer {
+        for (tensor_csrs.items) |*t| t.deinit(allocator);
+        tensor_csrs.deinit(allocator);
+    }
+
+    const n_layers: u32 = 32;
+    const n_experts: u32 = 8;
+    var total_outliers: u64 = 0;
+    var total_weights: u64 = 0;
+
+    for (0..n_layers) |layer| {
+        for (0..n_experts) |expert| {
+            // Analyze gate, up, down projections
+            const projections = [_][]const u8{ "ffn_gate", "ffn_up", "ffn_down" };
+            for (projections) |proj| {
+                const tensor_name = try std.fmt.allocPrint(
+                    allocator,
+                    "blk.{d}.{s}.{d}.weight",
+                    .{ layer, proj, expert },
+                );
+                defer allocator.free(tensor_name);
+
+                const q4k_info = q4k_loader.getTensor(tensor_name) orelse continue;
+                _ = q2k_loader.getTensor(tensor_name) orelse continue;
+
+                const n_elements = q4k_info.dimensions[0] * q4k_info.dimensions[1];
+                total_weights += n_elements;
+
+                // Allocate buffers for dequantized weights
+                const q4k_weights = try allocator.alloc(f32, n_elements);
+                defer allocator.free(q4k_weights);
+                const q2k_weights = try allocator.alloc(f32, n_elements);
+                defer allocator.free(q2k_weights);
+
+                // Dequantize both models
+                q4k_loader.dequantizeToF32(tensor_name, q4k_weights) catch |err| {
+                    log.warn("Failed to dequantize Q4K {s}: {s}", .{ tensor_name, @errorName(err) });
+                    continue;
+                };
+                q2k_loader.dequantizeToF32(tensor_name, q2k_weights) catch |err| {
+                    log.warn("Failed to dequantize Q2K {s}: {s}", .{ tensor_name, @errorName(err) });
+                    continue;
+                };
+
+                // Compute deltas and find significant ones (top 1% by magnitude)
+                const deltas = try allocator.alloc(f32, n_elements);
+                defer allocator.free(deltas);
+
+                var max_delta: f32 = 0;
+                for (0..n_elements) |i| {
+                    deltas[i] = q4k_weights[i] - q2k_weights[i];
+                    max_delta = @max(max_delta, @abs(deltas[i]));
+                }
+
+                // Build histogram for threshold calculation
+                const HISTOGRAM_BUCKETS = 10000;
+                var histogram: [HISTOGRAM_BUCKETS]u64 = [_]u64{0} ** HISTOGRAM_BUCKETS;
+                const bucket_width = if (max_delta > 0) max_delta / @as(f32, HISTOGRAM_BUCKETS) else 1.0;
+
+                for (deltas) |d| {
+                    const bucket = @min(
+                        @as(usize, @intFromFloat(@abs(d) / bucket_width)),
+                        HISTOGRAM_BUCKETS - 1,
+                    );
+                    histogram[bucket] += 1;
+                }
+
+                // Find 99th percentile threshold (top 1% outliers)
+                const target_count = n_elements * 99 / 100;
+                var cumulative: u64 = 0;
+                var threshold_bucket: usize = 0;
+                for (histogram, 0..) |count, i| {
+                    cumulative += count;
+                    if (cumulative >= target_count) {
+                        threshold_bucket = i;
+                        break;
+                    }
+                }
+                const threshold = @as(f32, @floatFromInt(threshold_bucket)) * bucket_width;
+
+                // Count outliers
+                var outlier_count: u32 = 0;
+                for (deltas) |d| {
+                    if (@abs(d) > threshold) outlier_count += 1;
+                }
+                total_outliers += outlier_count;
+
+                // Build CSR format
+                // GGUF stores weights as [n_embd, n_ff] for gate/up tensors
+                // Gate/Up kernel: input[n_embd] → output[n_ff], CSR rows=n_ff, cols=n_embd
+                // Down kernel: input[n_ff] → output[n_embd], CSR rows=n_embd, cols=n_ff
+                // Down projection dimensions are SWAPPED in GGUF: [n_ff, n_embd]
+                const is_down = std.mem.eql(u8, proj, "ffn_down");
+                const rows: u32 = if (is_down)
+                    @intCast(q4k_info.dimensions[1]) // n_embd for down
+                else
+                    @intCast(q4k_info.dimensions[1]); // n_ff for gate/up
+                const cols: u32 = if (is_down)
+                    @intCast(q4k_info.dimensions[0]) // n_ff for down
+                else
+                    @intCast(q4k_info.dimensions[0]); // n_embd for gate/up
+
+                var row_ptr = try allocator.alloc(u32, rows + 1);
+                var col_idx = try allocator.alloc(u16, outlier_count);
+                var values = try allocator.alloc(f16, outlier_count);
+
+                var nnz_idx: u32 = 0;
+                row_ptr[0] = 0;
+
+                // Original data is stored as [n_embd, n_ff] = [4096, 14336]
+                // We're building CSR with rows=n_ff, cols=n_embd (transposed view)
+                // So for CSR row r (output dim) and col c (input dim):
+                //   original index = c * n_ff + r  (since original layout is [n_embd][n_ff])
+                const original_dim1 = q4k_info.dimensions[1]; // n_ff = 14336
+                for (0..rows) |row| {
+                    for (0..cols) |col| {
+                        // Transpose: original[col][row] where original is [n_embd][n_ff]
+                        const idx = col * original_dim1 + row;
+                        if (@abs(deltas[idx]) > threshold) {
+                            col_idx[nnz_idx] = @intCast(col);
+                            values[nnz_idx] = @floatCast(deltas[idx]);
+                            nnz_idx += 1;
+                        }
+                    }
+                    row_ptr[row + 1] = nnz_idx;
+                }
+
+                const tensor_csr = hybrid_quantizer.TensorCSR{
+                    .name = try allocator.dupe(u8, tensor_name),
+                    .csr = .{
+                        .rows = rows,
+                        .cols = cols,
+                        .nnz = outlier_count,
+                        .row_ptr = row_ptr,
+                        .col_idx = col_idx,
+                        .values = values,
+                    },
+                };
+                try tensor_csrs.append(allocator, tensor_csr);
+            }
+        }
+
+        if (layer % 8 == 7) {
+            log.info("Analyzed layers 0-{d} ({d} tensors, {d:.2}M outliers)", .{
+                layer,
+                tensor_csrs.items.len,
+                @as(f64, @floatFromInt(total_outliers)) / 1e6,
+            });
+        }
+    }
+
+    log.info("Delta analysis complete: {d} tensors, {d:.2}M outliers ({d:.2}%)", .{
+        tensor_csrs.items.len,
+        @as(f64, @floatFromInt(total_outliers)) / 1e6,
+        @as(f64, @floatFromInt(total_outliers)) / @as(f64, @floatFromInt(total_weights)) * 100,
+    });
+
+    return try tensor_csrs.toOwnedSlice(allocator);
+}
+
+/// Analyze tensors using VIRTUAL Q2K simulation (no separate Q2K file needed!)
+/// This simulates Q2K quantization in-memory from Q4K weights.
+pub fn analyzeDeltaCorrectionsVirtual(
+    allocator: std.mem.Allocator,
+    q4k_loader: *gguf_loader.GGUFLoader,
+) ![]hybrid_quantizer.TensorCSR {
+    log.info("Starting VIRTUAL Q2 delta analysis (no Q2K file needed)...", .{});
+
+    var tensor_csrs = std.ArrayList(hybrid_quantizer.TensorCSR).initCapacity(allocator, 768) catch unreachable;
+    errdefer {
+        for (tensor_csrs.items) |*t| t.deinit(allocator);
+        tensor_csrs.deinit(allocator);
+    }
+
+    const n_layers: u32 = 32;
+    const n_experts: u32 = 8;
+    var total_outliers: u64 = 0;
+    var total_weights: u64 = 0;
+
+    for (0..n_layers) |layer| {
+        for (0..n_experts) |expert| {
+            // Analyze gate, up, down projections
+            const projections = [_][]const u8{ "ffn_gate", "ffn_up", "ffn_down" };
+            for (projections) |proj| {
+                const tensor_name = try std.fmt.allocPrint(
+                    allocator,
+                    "blk.{d}.{s}.{d}.weight",
+                    .{ layer, proj, expert },
+                );
+                defer allocator.free(tensor_name);
+
+                const q4k_info = q4k_loader.getTensor(tensor_name) orelse continue;
+
+                const n_elements = q4k_info.dimensions[0] * q4k_info.dimensions[1];
+                total_weights += n_elements;
+
+                // Allocate buffer for dequantized Q4K weights
+                const q4k_weights = try allocator.alloc(f32, n_elements);
+                defer allocator.free(q4k_weights);
+
+                // Dequantize Q4K to FP32
+                q4k_loader.dequantizeToF32(tensor_name, q4k_weights) catch |err| {
+                    log.warn("Failed to dequantize Q4K {s}: {s}", .{ tensor_name, @errorName(err) });
+                    continue;
+                };
+
+                // VIRTUAL Q2: Simulate Q2K quantization in memory
+                // 1. Quantize FP32 → Q2K
+                const q2k_bytes = try quantize.quantizeQ2K(allocator, q4k_weights);
+                defer allocator.free(q2k_bytes);
+
+                // 2. Dequantize Q2K → FP32 (simulated reconstruction)
+                const q2k_weights = try quantize.dequantizeQ2K(allocator, q2k_bytes, n_elements);
+                defer allocator.free(q2k_weights);
+
+                // Compute deltas: Q4K - Q2K (simulated)
+                const deltas = try allocator.alloc(f32, n_elements);
+                defer allocator.free(deltas);
+
+                var max_delta: f32 = 0;
+                for (0..n_elements) |i| {
+                    deltas[i] = q4k_weights[i] - q2k_weights[i];
+                    max_delta = @max(max_delta, @abs(deltas[i]));
+                }
+
+                // Build histogram for threshold calculation
+                const HISTOGRAM_BUCKETS = 10000;
+                var histogram: [HISTOGRAM_BUCKETS]u64 = [_]u64{0} ** HISTOGRAM_BUCKETS;
+                const bucket_width = if (max_delta > 0) max_delta / @as(f32, HISTOGRAM_BUCKETS) else 1.0;
+
+                for (deltas) |d| {
+                    const bucket = @min(
+                        @as(usize, @intFromFloat(@abs(d) / bucket_width)),
+                        HISTOGRAM_BUCKETS - 1,
+                    );
+                    histogram[bucket] += 1;
+                }
+
+                // Find 99th percentile threshold (top 1% outliers)
+                const target_count = n_elements * 99 / 100;
+                var cumulative: u64 = 0;
+                var threshold_bucket: usize = 0;
+                for (histogram, 0..) |count, i| {
+                    cumulative += count;
+                    if (cumulative >= target_count) {
+                        threshold_bucket = i;
+                        break;
+                    }
+                }
+                const threshold = @as(f32, @floatFromInt(threshold_bucket)) * bucket_width;
+
+                // Count outliers
+                var outlier_count: u32 = 0;
+                for (deltas) |d| {
+                    if (@abs(d) > threshold) outlier_count += 1;
+                }
+                total_outliers += outlier_count;
+
+                // Build CSR format (same as original function)
+                const is_down = std.mem.eql(u8, proj, "ffn_down");
+                const rows: u32 = if (is_down)
+                    @intCast(q4k_info.dimensions[1])
+                else
+                    @intCast(q4k_info.dimensions[1]);
+                const cols: u32 = if (is_down)
+                    @intCast(q4k_info.dimensions[0])
+                else
+                    @intCast(q4k_info.dimensions[0]);
+
+                var row_ptr = try allocator.alloc(u32, rows + 1);
+                var col_idx = try allocator.alloc(u16, outlier_count);
+                var values = try allocator.alloc(f16, outlier_count);
+
+                var nnz_idx: u32 = 0;
+                row_ptr[0] = 0;
+
+                const original_dim1 = q4k_info.dimensions[1];
+                for (0..rows) |row| {
+                    for (0..cols) |col| {
+                        const idx = col * original_dim1 + row;
+                        if (@abs(deltas[idx]) > threshold) {
+                            col_idx[nnz_idx] = @intCast(col);
+                            values[nnz_idx] = @floatCast(deltas[idx]);
+                            nnz_idx += 1;
+                        }
+                    }
+                    row_ptr[row + 1] = nnz_idx;
+                }
+
+                const tensor_csr = hybrid_quantizer.TensorCSR{
+                    .name = try allocator.dupe(u8, tensor_name),
+                    .csr = .{
+                        .rows = rows,
+                        .cols = cols,
+                        .nnz = outlier_count,
+                        .row_ptr = row_ptr,
+                        .col_idx = col_idx,
+                        .values = values,
+                    },
+                };
+                try tensor_csrs.append(allocator, tensor_csr);
+
+                // Per-tensor progress
+                const tensor_num = tensor_csrs.items.len;
+                if (tensor_num % 24 == 0) { // Every layer (8 experts × 3 projections)
+                    std.debug.print("    [{d}/768] {s} - {d} outliers\n", .{ tensor_num, tensor_name, outlier_count });
+                }
+            }
+        }
+
+        // Progress every layer
+        std.debug.print("  Layer {d}/32: {d} tensors, {d:.2}M outliers\n", .{
+            layer + 1,
+            tensor_csrs.items.len,
+            @as(f64, @floatFromInt(total_outliers)) / 1e6,
+        });
+    }
+
+    std.debug.print("\nVirtual Q2 analysis complete: {d} tensors, {d:.2}M outliers ({d:.2}%)\n", .{
+        tensor_csrs.items.len,
+        @as(f64, @floatFromInt(total_outliers)) / 1e6,
+        @as(f64, @floatFromInt(total_outliers)) / @as(f64, @floatFromInt(total_weights)) * 100,
+    });
+
+    return try tensor_csrs.toOwnedSlice(allocator);
+}
+
+/// Save CSR tensors to file
+pub fn saveCSR(_: std.mem.Allocator, tensors: []const hybrid_quantizer.TensorCSR, path: []const u8) !void {
+    const file = try std.fs.cwd().createFile(path, .{});
+    defer file.close();
+
+    // Header
+    _ = try file.write("ZELL_CSR");
+    const version: u32 = 1;
+    _ = try file.write(std.mem.asBytes(&version));
+    const tensor_count: u32 = @intCast(tensors.len);
+    _ = try file.write(std.mem.asBytes(&tensor_count));
+
+    // Each tensor
+    for (tensors) |tensor| {
+        // Name length + name
+        const name_len: u16 = @intCast(tensor.name.len);
+        _ = try file.write(std.mem.asBytes(&name_len));
+        _ = try file.write(tensor.name);
+
+        // Matrix dimensions
+        _ = try file.write(std.mem.asBytes(&tensor.csr.rows));
+        _ = try file.write(std.mem.asBytes(&tensor.csr.cols));
+        _ = try file.write(std.mem.asBytes(&tensor.csr.nnz));
+
+        // Row pointers
+        _ = try file.write(std.mem.sliceAsBytes(tensor.csr.row_ptr));
+
+        // Column indices
+        _ = try file.write(std.mem.sliceAsBytes(tensor.csr.col_idx));
+
+        // Values
+        _ = try file.write(std.mem.sliceAsBytes(tensor.csr.values));
+    }
+
+    log.info("Saved {d} CSR tensors to {s}", .{ tensors.len, path });
+}
+
+pub fn main() !void {
+    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
+    defer _ = gpa.deinit();
+    const allocator = gpa.allocator();
+
+    const args = try std.process.argsAlloc(allocator);
+    defer std.process.argsFree(allocator, args);
+
+    // Check for --virtual flag (Virtual Q2 mode)
