+//! Q2_K Quantizer for Zell
+//!
+//! Implements Q2_K quantization (FP32 → Q2_K) for the "Virtual Q2" strategy.
+//! This allows computing Q4K-Q2K deltas without needing a separate Q2K model file.
+//!
+//! Q2_K Format (84 bytes per 256 values):
+//!   - scales[16]: Each byte has 4-bit scale_low and 4-bit scale_high
+//!   - qs[64]: Packed 2-bit quantized values (4 per byte)
+//!   - d (f16): Global scale factor
+//!   - dmin (f16): Global minimum offset
+//!
+//! Dequantization: value = d * scale_low * quant - dmin * scale_high
+
+const std = @import("std");
+
+pub const Q2K_BLOCK_SIZE: usize = 256; // Values per block
+pub const Q2K_BLOCK_BYTES: usize = 84; // Bytes per block
+
+/// Quantize FP32 values to Q2_K format (GGML-compatible layout)
+/// Returns the quantized block (84 bytes)
+///
+/// GGML Q2_K layout uses interleaved storage:
+/// - 2 super-groups of 128 values each
+/// - qs[0..31] for super-group 0 (values 0-127)
+/// - qs[32..63] for super-group 1 (values 128-255)
+/// Within each super-group, values are interleaved by shift:
+/// - qs[l] bits 0-1: value[l]
+/// - qs[l] bits 2-3: value[l+32]
+/// - qs[l] bits 4-5: value[l+64]
+/// - qs[l] bits 6-7: value[l+96]
+pub fn quantizeQ2K_Block(src: *const [Q2K_BLOCK_SIZE]f32) [Q2K_BLOCK_BYTES]u8 {
+    var block: [Q2K_BLOCK_BYTES]u8 = undefined;
+
+    // Step 1: Find global min and max for the block
+    var global_min: f32 = src[0];
+    var global_max: f32 = src[0];
+    for (src) |v| {
+        global_min = @min(global_min, v);
+        global_max = @max(global_max, v);
+    }
+
+    // Step 2: Compute d and dmin
+    const range = global_max - global_min;
+    const d: f32 = if (range > 0) range / (15.0 * 3.0) else 1.0;
+    const dmin: f32 = if (global_min < 0) -global_min / 15.0 else 0.0;
+
+    // Step 3: Process 16 groups of 16 values (matching GGML scale layout)
+    var scales: [16]u8 = undefined;
+    var qs: [64]u8 = [_]u8{0} ** 64;
+
+    // Quantize all values first, then pack into GGML layout
+    var quants: [256]u8 = undefined;
+
+    for (0..16) |group_idx| {
+        const start = group_idx * 16;
+        const group = src[start..][0..16];
+
+        // Find local min/max for this group
+        var local_min: f32 = group[0];
+        var local_max: f32 = group[0];
+        for (group) |v| {
+            local_min = @min(local_min, v);
+            local_max = @max(local_max, v);
+        }
+
+        // Compute scale_low and scale_high for this group
+        const local_range = local_max - local_min;
+        const scale_low: u8 = if (d > 0 and local_range > 0)
+            @intFromFloat(@min(15.0, @max(0.0, local_range / (d * 3.0))))
+        else
+            1;
+
+        const scale_high: u8 = if (dmin > 0 and local_min < 0)
+            @intFromFloat(@min(15.0, @max(0.0, -local_min / dmin)))
+        else
+            0;
+
+        scales[group_idx] = (scale_high << 4) | scale_low;
+
+        // Quantize each value to 2 bits
+        const dl: f32 = d * @as(f32, @floatFromInt(scale_low));
+        const ml: f32 = dmin * @as(f32, @floatFromInt(scale_high));
+
+        for (0..16) |j| {
+            const v = group[j];
+            var quant: u8 = 0;
+            if (dl > 0) {
+                const q_float = (v + ml) / dl;
+                quant = @intFromFloat(@min(3.0, @max(0.0, q_float + 0.5)));
+            }
+            quants[start + j] = quant;
+        }
+    }
+
+    // Step 4: Pack quants into GGML interleaved layout
+    // Super-group 0 (values 0-127) → qs[0..31]
+    // Super-group 1 (values 128-255) → qs[32..63]
+    for (0..2) |super_group| {
+        const sg_offset: usize = super_group * 128;
+        const qs_base: usize = super_group * 32;
+
+        // Each byte qs[l] in range [0..15] or [32..47] holds:
+        // - bits 0-1: value[sg_offset + l]
+        // - bits 2-3: value[sg_offset + l + 32]
+        // - bits 4-5: value[sg_offset + l + 64]
+        // - bits 6-7: value[sg_offset + l + 96]
+        // And qs[l+16] holds values for l+16, l+48, l+80, l+112
+        for (0..16) |l| {
+            qs[qs_base + l] = quants[sg_offset + l] |
+                (quants[sg_offset + l + 32] << 2) |
+                (quants[sg_offset + l + 64] << 4) |
+                (quants[sg_offset + l + 96] << 6);
+            qs[qs_base + l + 16] = quants[sg_offset + l + 16] |
+                (quants[sg_offset + l + 48] << 2) |
+                (quants[sg_offset + l + 80] << 4) |
+                (quants[sg_offset + l + 112] << 6);
+        }
+    }
+
+    // Step 5: Pack the block
+    @memcpy(block[0..16], &scales);
+    @memcpy(block[16..80], &qs);
+
+    // Convert d and dmin to f16
+    const d_f16 = f32ToF16(d);
+    const dmin_f16 = f32ToF16(dmin);
+    std.mem.writeInt(u16, block[80..82], d_f16, .little);
+    std.mem.writeInt(u16, block[82..84], dmin_f16, .little);
+
+    return block;
+}
+
+/// Quantize a tensor from FP32 to Q2_K
+/// Returns allocated Q2_K bytes
+pub fn quantizeQ2K(allocator: std.mem.Allocator, src: []const f32) ![]u8 {
+    const num_values = src.len;
+    const num_blocks = (num_values + Q2K_BLOCK_SIZE - 1) / Q2K_BLOCK_SIZE;
+    const q2k_bytes = num_blocks * Q2K_BLOCK_BYTES;
+
+    var dst = try allocator.alloc(u8, q2k_bytes);
+    errdefer allocator.free(dst);
+
+    for (0..num_blocks) |block_idx| {
+        const start = block_idx * Q2K_BLOCK_SIZE;
+        const end = @min(start + Q2K_BLOCK_SIZE, num_values);
+
+        // Pad with zeros if necessary
+        var padded: [Q2K_BLOCK_SIZE]f32 = [_]f32{0} ** Q2K_BLOCK_SIZE;
+        @memcpy(padded[0..(end - start)], src[start..end]);
+
+        const block = quantizeQ2K_Block(&padded);
+        @memcpy(dst[block_idx * Q2K_BLOCK_BYTES ..][0..Q2K_BLOCK_BYTES], &block);
+    }
+
+    return dst;
+}
+
+/// Dequantize Q2_K block back to FP32 (for verification)
+pub fn dequantizeQ2K_Block(block: *const [Q2K_BLOCK_BYTES]u8, dest: *[Q2K_BLOCK_SIZE]f32) void {
+    const scales = block[0..16];
+    const qs = block[16..80];
+    const d_bits = std.mem.readInt(u16, block[80..82], .little);
+    const dmin_bits = std.mem.readInt(u16, block[82..84], .little);
+
+    const d = f16ToF32(d_bits);
+    const dmin = f16ToF32(dmin_bits);
+
+    for (0..16) |group_idx| {
+        const scale_byte = scales[group_idx];
+        const sc_low: f32 = @floatFromInt(scale_byte & 0xF);
+        const sc_high: f32 = @floatFromInt(scale_byte >> 4);
+
+        const dl = d * sc_low;
+        const ml = dmin * sc_high;
+
+        const start = group_idx * 16;
+        for (0..16) |j| {
+            const byte_idx = start / 4 + j / 4;
+            const bit_offset: u3 = @intCast((j % 4) * 2);
+            const quant: f32 = @floatFromInt((qs[byte_idx] >> bit_offset) & 0x3);
+            dest[start + j] = dl * quant - ml;
+        }
+    }
+}
+
+/// Dequantize Q2_K tensor to FP32
+pub fn dequantizeQ2K(allocator: std.mem.Allocator, src: []const u8, num_values: usize) ![]f32 {
+    const num_blocks = num_values / Q2K_BLOCK_SIZE;
+    var dst = try allocator.alloc(f32, num_values);
+    errdefer allocator.free(dst);
+
+    for (0..num_blocks) |block_idx| {
+        const block = src[block_idx * Q2K_BLOCK_BYTES ..][0..Q2K_BLOCK_BYTES];
+        const out = dst[block_idx * Q2K_BLOCK_SIZE ..][0..Q2K_BLOCK_SIZE];
+        dequantizeQ2K_Block(block, out);
+    }
+
+    return dst;
+}
+
+/// Convert f32 to f16 bits
+fn f32ToF16(f: f32) u16 {
+    const f16_val: f16 = @floatCast(f);
+    return @bitCast(f16_val);
+}
+
+/// Convert f16 bits to f32
+fn f16ToF32(bits: u16) f32 {
+    const f16_val: f16 = @bitCast(bits);
+    return @floatCast(f16_val);
+}
+
+// ============================================================================
+// Tests
+// ============================================================================
+
+test "Q2K round-trip" {
+    const allocator = std.testing.allocator;
+
+    // Create test data
+    var original: [256]f32 = undefined;
+    for (0..256) |i| {
+        original[i] = @as(f32, @floatFromInt(i)) / 128.0 - 1.0; // Range: -1 to ~1
+    }
+
+    // Quantize
+    const q2k = try quantizeQ2K(allocator, &original);
+    defer allocator.free(q2k);
+
+    // Dequantize
+    const reconstructed = try dequantizeQ2K(allocator, q2k, 256);
+    defer allocator.free(reconstructed);
+
+    // Check error is reasonable (Q2K has significant quantization error)
+    var max_error: f32 = 0;
+    for (0..256) |i| {
+        const err = @abs(original[i] - reconstructed[i]);
+        max_error = @max(max_error, err);
+    }
+
+    // Q2K is 2-bit, so expect ~10-20% error
+    try std.testing.expect(max_error < 0.5);
+}
